$(document).ready(function () {


    var responsiveSize;
    var suggestedPages;
    var _rwaloggedin = 0;
    var _rwaloginjson;

    //console.log('Loaded');
    setResponsiveSize();
    buildLinkBlocks();
    fixLinkBlockHeights();
    loginCheck();
    resizeListner();
    setupInPageSearch();
    loadSuggestedPages();
    fixPlaceholder();
    addSearchClear();
    fixJslinks();
    feedbackLinks();




    if (navigator.platform.match('Mac') !== null) {
        $('body').addClass('typography-supported');
    }

    function resizeListner() {
        // Listen for resize changes
        window.onresize = function () {
            oldResponsiveSize = responsiveSize;
            setResponsiveSize();
            if (oldResponsiveSize != responsiveSize) {
                fixLinkBlockHeights();
                //console.log('responsiveSize changed');
            }
        };


    }

    function setResponsiveSize() {
        if ($(window).width() < 768) {
            responsiveSize = 'sm';
        }
        else if ($(window).width() > 768 && $(window).width() <= 992) {
            responsiveSize = 'md';
        }
        else if ($(window).width() > 992 && $(window).width() <= 1200) {
            responsiveSize = 'lg';
        }
        else {
            // do something for huge screens
        }
    }


    function loginCheck() {

        $.getJSON("https://www2.richmond.gov.uk/Account/LoginStatusHTMLHPShort.aspx?callback=?",
        //$.getJSON("https://www2.richmond.gov.uk/Account/LoginStatusHTMLHP.aspx?callback=?",
        null,
        function (json) {
            //alert('rwa');
            if (json.AccountStatus.LoggedIn == "true") {
                //_uprn = json.AccountData.UPRN;
                //doLogin(json);
                _rwaloggedin = 1;
                _rwaloginjson = json;
                //prepareFormLinks();
